INSERT INTO TB_BBS_BRD (
    BRD_CD, BRD_NM, BRD_TYPE, BRD_PROP_BINARY, BRD_LIST_URL, BRD_DSCR
  , USE_YN, DEL_YN, CRE_USR_CD, CRE_DTM, UPD_USR_CD, UPD_DTM
) VALUES (
    #{brdCd}, #{brdNm}, 0, #{brdPropBinary}, #{brdListUrl}, #{brdDscr}
  , #{useYn}, 'N', #{ssnUsrCd}, SYSDATE(), #{ssnUsrCd}, SYSDATE()
)
ON DUPLICATE KEY UPDATE
    BRD_NM          = #{brdNm}
  , BRD_PROP_BINARY = #{brdPropBinary}
  , BRD_LIST_URL    = #{brdListUrl}
  , BRD_DSCR        = #{brdDscr}
  , USE_YN          = #{useYn}
  , UPD_USR_CD      = #{ssnUsrCd}
  , UPD_DTM         = SYSDATE()
